var rowAndMaximumOnes = function(mat) {
    let bestRow = 0;
    let bestCount = -1;
    for (let i = 0; i < mat.length; i++) {
        let c = 0;
        for (const v of mat[i]) c += v;
        if (c > bestCount) {
            bestCount = c;
            bestRow = i;
        }
    }
    return [bestRow, bestCount];
};
